CREATE FUNCTION public.fn_postgresql_order_item_total(order_id_value VARCHAR)
RETURNS NUMERIC
LANGUAGE plpgsql
AS $$
DECLARE
    total_value NUMERIC;
BEGIN
    SELECT COALESCE(SUM(NULLIF("Net_Selling_Price", '')::NUMERIC), 0)
    INTO total_value
    FROM public.order_items
    WHERE "Order_ID" = order_id_value;

    RETURN total_value;
END;
$$;
